import Starling from '../src/base';
import { EN_TXT_CDN_ios, EN_TXT_CDN_frontend, EN_TXT_CDN_frontend_zh } from './remote-demo-en';
const request = jest.fn();

const optionsCdn = {
  apiKey: 'de2eef103c0d11e99e27758535c50ad2',
  locale: 'en',
  namespace: 'frontend',
  zoneHost: '',
  timeout: 5000,
  cdn: 'https://lf3-cdn-tos.draftstatic.com/obj/ies.fe.starling/',
};

describe('集成测试 - Starling Client', () => {
  test('正常拉取 文案', async () => {
    request.mockReturnValue({
      data: {
        status: 200,
        message: { Version: '1', Lang: 'en', Data: EN_TXT_CDN_frontend, Updated: true },
      },
    });
    const starling = new Starling({
      ...optionsCdn,
      request,
    });

    const texts = await starling.load();

    expect(texts).toEqual(EN_TXT_CDN_frontend);
  });

  test('正常拉取 zh 文案 超时error', async () => {
    const text = await new Starling(
      Object.assign({}, optionsCdn, { locale: 'zh', timeout: 1, request })
    )
      .load()
      .catch((e) => {
        expect(e.code).toEqual('ECONNABORTED');
      });
  });

  test('模拟 onerror', async () => {
    const text = await new Starling(
      Object.assign({}, optionsCdn, {
        locale: 'zh',
        request,
        cdn: 'https://lf3-cdn-tos.draftstatic.com/obj/ies.fe.starling/_2222',
      })
    )
      .load()
      .catch((e) => {
        expect(e.message).toEqual('Network Error');
      });
  });

  test('正常拉取 en 文案', async () => {
    request.mockReturnValue({
      data: {
        status: 200,
        message: { Version: '1', Lang: 'en', Data: EN_TXT_CDN_frontend, Updated: true },
      },
    });
    const text = await new Starling(
      Object.assign({}, optionsCdn, { locale: 'en', request })
    ).load();

    expect(text).toEqual(expect.objectContaining(EN_TXT_CDN_frontend));
  });

  test('拉取不存在的 ko 文案', async () => {
    const text = await new Starling(
      Object.assign({}, optionsCdn, { locale: 'ko', request })
    ).load();
    expect(text).toEqual(expect.objectContaining({}));
  });

  test('拉取错误 api key 的 en 文案', async () => {
    return new Starling(
      Object.assign({}, optionsCdn, {
        locale: 'en',
        api_key: '123',
        request,
      })
    )
      .load()
      .then(
        (value) => {},
        (reason) => {
          // 没有缓存，结果应当是空对象
          expect(reason.response.data).toEqual(expect.objectContaining({}));
        }
      );
  });

  test('拉取错误 api key 的 zh 文案', async () => {
    return new Starling(
      Object.assign({}, optionsCdn, {
        locale: 'zh',
        api_key: '123',
        request,
      })
    )
      .load()
      .then(
        (value) => {},
        (reason) => {
          // 没有缓存，结果应当是空对象
          expect(reason.response.data).toEqual(expect.objectContaining({}));
        }
      );
  });

  test('拉取错误 namespace 的 en 文案', async () => {
    return new Starling(
      Object.assign({}, optionsCdn, {
        locale: 'en',
        namespace: 'wangqinhong',
        request,
      })
    )
      .load()
      .then(
        (value) => {
          // 空间错误，后端返回 {"message":{"Data":{},"Version":"0","Updated":true,"Lang":"en"},"status":200}
          // 所以 value 应当是空对象
          expect(value).toEqual(expect.objectContaining({}));
        },
        (reason) => {}
      );
  });

  test('拉取错误 namespace 的 zh 文案', async () => {
    return new Starling(
      Object.assign({}, optionsCdn, {
        locale: 'zh',
        namespace: 'wangqinhong',
        request,
      })
    )
      .load()
      .then(
        (value) => {
          // 空间错误，后端返回 {"message":{"Data":{},"Version":"0","Updated":true,"Lang":"zh"},"status":200}
          // 所以 value 应当是空对象
          expect(value).toEqual(expect.objectContaining({}));
        },
        (reason) => {}
      );
  });

  test('load - 成功 - CDN 配置 - 多空间拉取', async () => {
    const starling = new Starling({
      ...optionsCdn,
      namespace: ['frontend', 'ios'],
    });

    const texts = await starling.load();

    expect(texts).toEqual({
      ...EN_TXT_CDN_frontend,
      ...EN_TXT_CDN_ios,
    });
  });

  test('load - 成功 - CDN 配置 - format: splitted', async () => {
    const starling = new Starling({
      ...optionsCdn,
      namespace: ['frontend'],
      format: 'splitted',
    });
    // when
    const texts = await starling.load();
    // then
    expect(texts).toEqual({
      frontend: {
        texts: EN_TXT_CDN_frontend,
        version: '1720082294362255000',
        lang: 'en',
      },
    });
  });

  test('load - 成功 - CDN 配置 - 兜底语种 - 单个兜底en', async () => {
    const starling = new Starling({
      ...optionsCdn,
      locale: 'en',
      fallbackLang: ['en'],
    });

    const texts = await starling.load();

    expect(texts).toEqual(EN_TXT_CDN_frontend);
  });

  test('load - 成功 - CDN 配置 - 兜底语种 - 多个兜底 - 优先获取zh', async () => {
    const starling = new Starling({
      ...optionsCdn,
      locale: 'ab',
      fallbackLang: ['jb', 'zh', 'en'],
    });

    const texts = await starling.load();

    expect(texts).toEqual(EN_TXT_CDN_frontend_zh);
  });

  test('load - 成功 - CDN 配置 - 兜底语种 - 多个兜底 - (只有zh有数据)', async () => {
    const starling = new Starling({
      ...optionsCdn,
      locale: 'ab',
      namespace: ['frontend'],
      fallbackLang: ['jb', 'ff', 'zh', 'zz'],
    });

    const texts = await starling.load();

    expect(texts).toEqual(EN_TXT_CDN_frontend_zh);
  });

  test('load - 成功 - CDN 配置 - 兜底语种 - 多个兜底 - 全部失败，则空返回', async () => {
    const starling = new Starling({
      ...optionsCdn,
      locale: 'ab',
      fallbackLang: ['jb', 'ff', 'aa', 'abcd', 'zz'],
    });

    const texts = await starling.load();

    expect(texts).toEqual({});
  });
});
